// Kali Linux security operations for home network protection

const input = $input.first().json;
const operation = input.operation; // scan, monitor, assess, defend, audit
const target = input.target || "192.168.1.0/24";

const securityOps = {
  scan: {
    command: `nmap -sV -sC ${target}`,
    description: "Network discovery and service detection"
  },
  monitor: {
    command: `tcpdump -i eth0 -w capture.pcap`,
    description: "Network traffic monitoring"
  },
  assess: {
    command: `nikto -h ${target}`,
    description: "Web vulnerability scanning"
  },
  defend: {
    command: `fail2ban-client status`,
    description: "Intrusion prevention status"
  },
  audit: {
    command: `lynis audit system`,
    description: "System security audit"
  },
  firewall: {
    command: `ufw status verbose`,
    description: "Firewall configuration check"
  },
  wireless: {
    command: `airmon-ng start wlan0`,
    description: "Wireless network monitoring"
  }
};

const op = securityOps[operation] || securityOps.scan;

return {
  operation: operation,
  target: target,
  command: op.command,
  description: op.description,
  warning: "Execute security operations responsibly and only on authorized networks",
